// الگوریتم پیچیده امتیازدهی و انتخاب بهترین تکنسین
const inputData = $input.first().json;
const customerLat = parseFloat(inputData.customer_lat);
const customerLon = parseFloat(inputData.customer_lon);
const aiAnalysis = JSON.parse(inputData.content);
const requiredParts = aiAnalysis.required_parts || [];

// شبیه‌سازی داده‌های تکنسین‌ها (در واقعیت از PostgreSQL می‌آید)
const technicians = [
  { id: 'T1', name: 'Ali Rezaei', lat: 35.70, lon: 51.40, skills: ['AC', 'Heater'], current_load: 2, van_inventory: ['freon', 'thermostat'] },
  { id: 'T2', name: 'Mohammad Ahmadi', lat: 35.75, lon: 51.45, skills: ['AC', 'Refrigerator'], current_load: 0, van_inventory: ['compressor', 'freon'] },
  { id: 'T3', name: 'Sara Karimi', lat: 35.68, lon: 51.38, skills: ['Heater'], current_load: 4, van_inventory: ['igniter'] }
];

let bestTech = null;
let highestScore = -999;

// تابع محاسبه فاصله (Haversine Formula)
function getDistance(lat1, lon1, lat2, lon2) {
  const R = 6371; // شعاع زمین به کیلومتر
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

technicians.forEach(tech => {
  // 1. بررسی تخصص
  const hasSkill = tech.skills.includes(aiAnalysis.device_type);
  if (!hasSkill) return;

  // 2. محاسبه فاصله
  const distance = getDistance(customerLat, customerLon, tech.lat, tech.lon);
  const proximityScore = Math.max(0, 100 - (distance * 5)); // هر کیلومتر 5 امتیاز کسر می‌شود

  // 3. بررسی موجودی قطعات
  const partsAvailable = requiredParts.every(part => tech.van_inventory.includes(part));
  const partsScore = partsAvailable ? 100 : 0;

  // 4. محاسبه امتیاز نهایی (وزن‌دهی: 40% فاصله، 40% قطعات، 20% بار کاری معکوس)
  const loadPenalty = tech.current_load * 15;
  const totalScore = (proximityScore * 0.4) + (partsScore * 0.4) + ((100 - loadPenalty) * 0.2);

  if (totalScore > highestScore) {
    highestScore = totalScore;
    bestTech = { ...tech, distance: distance.toFixed(2), partsAvailable, score: totalScore.toFixed(2) };
  }
});

// محاسبه قیمت داینامیک
const basePrice = aiAnalysis.urgency === 'critical' ? 150 : 100;
const travelFee = bestTech ? parseFloat(bestTech.distance) * 1.5 : 0;
const partsFee = requiredParts.length * 25;
const finalPrice = (basePrice + travelFee + partsFee).toFixed(2);

return [{
  json: {
    customer_name: inputData.customer_name,
    customer_address: inputData.customer_address,
    ai_analysis: aiAnalysis,
    assigned_technician: bestTech,
    final_price_usd: finalPrice,
    parts_available: bestTech ? bestTech.partsAvailable : false
  }
}];

